impl<T> JoinHandle<T>
where
    T: Send + 'static,
{
    pub(crate) fn poll_join(&mut self, cx: &mut Context<'_>) -> Poll<Result<T, JoinError>> {
        let _ = cx.waker();
        match self.output.take() {
            Some(value) => Poll::Ready(Ok(value)),
            None => Poll::Pending,
        }
    }
}

